import React, { useState, useRef, useEffect } from 'react';

function DrawingCanvas({ cameraData, onSave, onBack }) {
  // Kiểm tra cameraData có tồn tại không
  if (!cameraData) {
    return (
      <div style={{ padding: '20px', textAlign: 'center' }}>
        <p>Không có dữ liệu camera. Vui lòng quay lại.</p>
        <button onClick={onBack}>Quay lại</button>
      </div>
    );
  }

  // Kiểm tra imagePreview có tồn tại không
  if (!cameraData.imagePreview) {
    return (
      <div style={{ padding: '20px', textAlign: 'center' }}>
        <p>Đang tải ảnh...</p>
        <button onClick={onBack}>Quay lại</button>
      </div>
    );
  }

  // State
  const [currentStep, setCurrentStep] = useState(1);
  const [drawing, setDrawing] = useState(false);
  const [lines, setLines] = useState([]);
  const [polyPoints, setPolyPoints] = useState([]);
  const [ix, setIx] = useState(-1);
  const [iy, setIy] = useState(-1);
  const [showPreview, setShowPreview] = useState(false);
  const [imageLoaded, setImageLoaded] = useState(false);
  const [canvasReady, setCanvasReady] = useState(false);

  const canvasRef = useRef(null);
  const imageRef = useRef(null);

  const FIXED_WIDTH = 1920;
  const FIXED_HEIGHT = 1080;

  // Generate UUID
  const generateUUID = () => {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  };

  // Format output
  const generateOutput = () => {
    const axis = lines[0] ? [
      Number((lines[0][0] / FIXED_WIDTH).toFixed(3)),
      Number((lines[0][1] / FIXED_HEIGHT).toFixed(3)),
      Number((lines[0][2] / FIXED_WIDTH).toFixed(3)),
      Number((lines[0][3] / FIXED_HEIGHT).toFixed(3))
    ] : [0, 0, 0, 0];

    const coord = lines[1] ? [
      Number((lines[1][0] / FIXED_WIDTH).toFixed(3)),
      Number((lines[1][1] / FIXED_HEIGHT).toFixed(3)),
      Number((lines[1][2] / FIXED_WIDTH).toFixed(3)),
      Number((lines[1][3] / FIXED_HEIGHT).toFixed(3))
    ] : [0, 0, 0, 0];

    const zone = polyPoints.length >= 4 ? 
      polyPoints.slice(0, 4).flatMap(p => [
        Number((p.x / FIXED_WIDTH).toFixed(3)),
        Number((p.y / FIXED_HEIGHT).toFixed(3))
      ]) : [0, 0, 0, 0, 0, 0, 0, 0];

    return {
      list_camera: [
        {
          cam_info: {
            url: cameraData.rtspUrl || "",
            cam_id: generateUUID()
          },
          config: {
            direction: [],
            heatmap: {},
            layout: {},
            zone: [{
              ID: generateUUID(),
              type: 1,
              axis: axis,
              coord: coord
            }],
            reid: {
              faiss_switch: 0.6,
              faiss_staff_db: 0.8
            }
          }
        }
      ]
    };
  };

  // Xử lý resize ảnh
  useEffect(() => {
    if (cameraData.imagePreview && imageRef.current) {
      const img = new Image();
      img.src = cameraData.imagePreview;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = FIXED_WIDTH;
        canvas.height = FIXED_HEIGHT;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, FIXED_WIDTH, FIXED_HEIGHT);

        imageRef.current.src = canvas.toDataURL();
        setImageLoaded(true);

        if (canvasRef.current) {
          canvasRef.current.width = FIXED_WIDTH;
          canvasRef.current.height = FIXED_HEIGHT;
          setCanvasReady(true);
        }
      };
    }
  }, [cameraData.imagePreview]);

  // Vẽ lại tất cả
  const redrawAll = () => {
    if (!canvasRef.current || !canvasReady) return;

    const ctx = canvasRef.current.getContext('2d');
    ctx.clearRect(0, 0, FIXED_WIDTH, FIXED_HEIGHT);

    // Vẽ axis
    if (lines[0]) {
      const [x1, y1, x2, y2] = lines[0];
      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 3;
      ctx.stroke();
    }

    // Vẽ coord
    if (lines[1]) {
      const [x1, y1, x2, y2] = lines[1];
      drawArrow(ctx, x1, y1, x2, y2, '#ff0000', 4);
    }

    // Vẽ polygon
    if (polyPoints.length > 0) {
      ctx.strokeStyle = '#ff4444';
      ctx.lineWidth = 2;

      for (let i = 0; i < polyPoints.length - 1; i++) {
        ctx.beginPath();
        ctx.moveTo(polyPoints[i].x, polyPoints[i].y);
        ctx.lineTo(polyPoints[i+1].x, polyPoints[i+1].y);
        ctx.stroke();
      }

      if (polyPoints.length === 4) {
        ctx.beginPath();
        ctx.moveTo(polyPoints[3].x, polyPoints[3].y);
        ctx.lineTo(polyPoints[0].x, polyPoints[0].y);
        ctx.stroke();

        ctx.fillStyle = 'rgba(255, 68, 68, 0.1)';
        ctx.beginPath();
        ctx.moveTo(polyPoints[0].x, polyPoints[0].y);
        ctx.lineTo(polyPoints[1].x, polyPoints[1].y);
        ctx.lineTo(polyPoints[2].x, polyPoints[2].y);
        ctx.lineTo(polyPoints[3].x, polyPoints[3].y);
        ctx.closePath();
        ctx.fill();
      }

      polyPoints.forEach((point, index) => {
        ctx.beginPath();
        ctx.arc(point.x, point.y, 6, 0, 2 * Math.PI);
        ctx.fillStyle = '#ff4444';
        ctx.fill();
        ctx.strokeStyle = 'white';
        ctx.lineWidth = 2;
        ctx.stroke();

        ctx.fillStyle = 'white';
        ctx.font = 'bold 14px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(index + 1, point.x, point.y);
      });
    }
  };

  // Vẽ mũi tên
  const drawArrow = (ctx, fromX, fromY, toX, toY, color, width) => {
    const headLength = 20;
    const angle = Math.atan2(toY - fromY, toX - fromX);

    ctx.beginPath();
    ctx.moveTo(fromX, fromY);
    ctx.lineTo(toX, toY);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(toX, toY);
    ctx.lineTo(
      toX - headLength * Math.cos(angle - Math.PI / 6),
      toY - headLength * Math.sin(angle - Math.PI / 6)
    );
    ctx.lineTo(
      toX - headLength * Math.cos(angle + Math.PI / 6),
      toY - headLength * Math.sin(angle + Math.PI / 6)
    );
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
  };

  // Xử lý mouse down
  const handleMouseDown = (e) => {
    e.preventDefault();
    if (!canvasRef.current || !canvasReady) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    if (currentStep === 3) {
      if (polyPoints.length < 4) {
        const newPoint = { x, y };
        setPolyPoints([...polyPoints, newPoint]);
      }
    } else {
      setDrawing(true);
      setIx(x);
      setIy(y);
    }
  };

  // Xử lý mouse move
  const handleMouseMove = (e) => {
    e.preventDefault();
    if (!drawing || !canvasRef.current || !canvasReady || currentStep === 3) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    const ctx = canvasRef.current.getContext('2d');
    redrawAll();

    ctx.beginPath();
    ctx.moveTo(ix, iy);
    ctx.lineTo(x, y);

    if (currentStep === 1) {
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 2;
      ctx.setLineDash([5, 5]);
      ctx.stroke();
      ctx.setLineDash([]);
    } else if (currentStep === 2) {
      drawArrow(ctx, ix, iy, x, y, '#ff0000', 2);
    }
  };

  // Xử lý mouse up
  const handleMouseUp = (e) => {
    e.preventDefault();
    if (!drawing || !canvasRef.current || !canvasReady || currentStep === 3) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    const newLine = [ix, iy, x, y];
    setLines([...lines, newLine]);
    setDrawing(false);

    if (currentStep === 1) {
      setCurrentStep(2);
    } else if (currentStep === 2) {
      setCurrentStep(3);
    }
  };

  // Redraw khi lines hoặc polyPoints thay đổi
  useEffect(() => {
    if (canvasReady) {
      redrawAll();
    }
  }, [lines, polyPoints, canvasReady]);

  const handleComplete = () => {
    if (lines.length < 2) {
      alert('Chưa vẽ đủ Axis và Coord!');
      return;
    }
    if (polyPoints.length < 4) {
      alert('Chưa vẽ đủ 4 điểm Polygon!');
      return;
    }
    setShowPreview(true);
  };

  const handleSave = () => {
    const output = generateOutput();
    onSave(output.list_camera[0].config);
  };

  const handleReset = () => {
    setLines([]);
    setPolyPoints([]);
    setCurrentStep(1);
    setDrawing(false);
    setShowPreview(false);
  };

  const isStep1Completed = lines.length >= 1;
  const isStep2Completed = lines.length >= 2;
  const isStep3Completed = polyPoints.length >= 4;
  const canComplete = isStep1Completed && isStep2Completed && isStep3Completed;

  return (
    <div className="drawing-canvas">
      {/* Steps */}
      <div className="steps">
        <div className={`step ${currentStep === 1 ? 'active' : ''} ${isStep1Completed ? 'completed' : ''}`}>
          <div className="step-number">1</div>
          <div className="step-info">
            <div className="step-title">Vẽ Axis</div>
            <div className="step-status">
              {isStep1Completed ? '✅ Hoàn thành' : '⏳ Chưa vẽ'}
            </div>
          </div>
        </div>

        <div className={`step ${currentStep === 2 ? 'active' : ''} ${isStep2Completed ? 'completed' : ''}`}>
          <div className="step-number">2</div>
          <div className="step-info">
            <div className="step-title">Vẽ Coord</div>
            <div className="step-status">
              {isStep2Completed ? '✅ Hoàn thành' : '⏳ Chưa vẽ'}
            </div>
          </div>
        </div>

        <div className={`step ${currentStep === 3 ? 'active' : ''} ${isStep3Completed ? 'completed' : ''}`}>
          <div className="step-number">3</div>
          <div className="step-info">
            <div className="step-title">Vẽ Polygon</div>
            <div className="step-status">
              {isStep3Completed ? '✅ Hoàn thành' : `⏳ ${polyPoints.length}/4 điểm`}
            </div>
          </div>
        </div>
      </div>

      {/* Canvas */}
      <div className="canvas-container">
        <img 
          ref={imageRef} 
          alt="Camera" 
          style={{ display: 'none' }}
        />
        {canvasReady ? (
          <canvas
            ref={canvasRef}
            width={FIXED_WIDTH}
            height={FIXED_HEIGHT}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={() => setDrawing(false)}
            style={{
              width: '100%',
              height: 'auto',
              cursor: currentStep === 3 && polyPoints.length < 4 ? 'crosshair' : 'default',
              border: '2px solid #ddd',
              borderRadius: '8px',
              background: '#f0f0f0'
            }}
          />
        ) : (
          <div style={{ padding: '100px', textAlign: 'center', border: '2px solid #ddd', borderRadius: '8px' }}>
            <p>Đang tải canvas...</p>
          </div>
        )}
      </div>

      {/* Status */}
      <div className="current-step">
        <span>Bước hiện tại: </span>
        <strong>
          {currentStep === 1 && 'Vẽ Axis (line đen)'}
          {currentStep === 2 && 'Vẽ Coord (mũi tên đỏ)'}
          {currentStep === 3 && `Vẽ Polygon (${polyPoints.length}/4 điểm)`}
        </strong>
      </div>

      {/* Nút hoàn thành */}
      <button 
        className="btn-complete"
        onClick={handleComplete}
        disabled={!canComplete}
      >
        {canComplete ? '✨ Hoàn thành config' : 'Vẽ đủ 3 bước để hoàn thành'}
      </button>

      {/* Preview */}
      {showPreview && (
        <div className="preview">
          <h4>📋 Kết quả:</h4>
          <pre>{JSON.stringify(generateOutput(), null, 2)}</pre>

          <div className="preview-actions">
            <button onClick={() => {
              navigator.clipboard.writeText(JSON.stringify(generateOutput(), null, 2));
              alert('Đã copy!');
            }}>
              Copy JSON
            </button>
            <button onClick={handleSave}>
              Lưu camera
            </button>
          </div>
        </div>
      )}

      {/* Actions */}
      <div className="actions">
        <button onClick={onBack}>← Quay lại</button>
        <button onClick={handleReset}>⟲ Vẽ lại</button>
      </div>

      <style jsx>{`
        .drawing-canvas {
          padding: 20px;
        }

        .steps {
          display: flex;
          gap: 10px;
          margin-bottom: 20px;
        }

        .step {
          flex: 1;
          display: flex;
          align-items: center;
          gap: 10px;
          padding: 10px;
          background: #f5f5f5;
          border-radius: 8px;
          border: 2px solid #ddd;
        }

        .step.active {
          border-color: #007bff;
          background: #e3f2fd;
        }

        .step.completed {
          border-color: #28a745;
          background: #d4edda;
        }

        .step-number {
          width: 30px;
          height: 30px;
          background: #007bff;
          color: white;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          font-weight: bold;
        }

        .step.completed .step-number {
          background: #28a745;
        }

        .step-info {
          flex: 1;
        }

        .step-title {
          font-weight: 600;
          font-size: 14px;
        }

        .step-status {
          font-size: 12px;
          color: #666;
        }

        .canvas-container {
          margin-bottom: 20px;
        }

        .current-step {
          padding: 10px;
          background: #e9ecef;
          border-radius: 4px;
          margin-bottom: 20px;
          text-align: center;
        }

        .btn-complete {
          width: 100%;
          padding: 15px;
          background: linear-gradient(135deg, #667eea, #764ba2);
          color: white;
          border: none;
          border-radius: 8px;
          font-size: 16px;
          font-weight: 600;
          cursor: pointer;
          margin-bottom: 20px;
        }

        .btn-complete:disabled {
          background: #ccc;
          cursor: not-allowed;
        }

        .preview {
          background: #1e1e1e;
          color: white;
          padding: 15px;
          border-radius: 8px;
          margin-bottom: 20px;
        }

        .preview pre {
          background: #2d2d2d;
          color: #d4d4d4;
          padding: 10px;
          border-radius: 4px;
          overflow-x: auto;
          font-size: 12px;
        }

        .preview-actions {
          display: flex;
          gap: 10px;
          margin-top: 10px;
        }

        .preview-actions button {
          flex: 1;
          padding: 8px;
          border: none;
          border-radius: 4px;
          cursor: pointer;
        }

        .actions {
          display: flex;
          gap: 10px;
        }

        .actions button {
          flex: 1;
          padding: 10px;
          border: none;
          border-radius: 4px;
          cursor: pointer;
        }

        .actions button:first-child {
          background: #6c757d;
          color: white;
        }

        .actions button:last-child {
          background: #ffc107;
          color: #212529;
        }
      `}</style>
    </div>
  );
}

export default DrawingCanvas;
